type RuntimeDependency = { id: string; name: string; version: string; url: string; purpose: string; required: boolean; status: 'pending' | 'ready' | 'degraded' | 'failed' };
export function buildRuntimeDependencyManifest(input: ReportInput): RuntimeDependency[] {
  const dependencySource = 'https://cdn.jsdelivr.net/npm/@highlightjs/cdn-assets@11.11.1/styles/github-dark.min.css and a deliberately long string that must not force body-level horizontal overflow in the generated report';
  return runtimeDependencies.map((dependency) => ({ ...dependency, status: 'pending', purpose: `${dependency.purpose} via ${dependencySource}` }));
}
